// Parse admin alert payload
// Supports: NEW_ORDER, PAYMENT_SUBMITTED, LOW_STOCK, NEW_RETURN, NEW_REVIEW, NEW_MERCHANT

const body = $input.first().json.body || $input.first().json;
let payload = body;

// Supabase Database Webhook format (orders table INSERT)
if (body.type === 'INSERT' && body.table === 'orders') {
  const record = body.record || {};
  payload = {
    alert_type: 'NEW_ORDER',
    data: {
      order_no: record.order_no,
      customer_name: record.customer_name,
      customer_phone: record.customer_phone,
      total: record.total,
      payment_state: record.payment_state,
      delivery_method: record.delivery_method,
      item_count: record.item_count || 0,
      created_at: record.created_at
    }
  };
}
// Supabase Database Webhook format (orders table UPDATE - payment submitted)
else if (body.type === 'UPDATE' && body.table === 'orders') {
  const record = body.record || {};
  const old_record = body.old_record || {};

  if (old_record.payment_state !== record.payment_state && record.payment_state === 'SUBMITTED') {
    payload = {
      alert_type: 'PAYMENT_SUBMITTED',
      data: {
        order_no: record.order_no,
        customer_name: record.customer_name,
        total: record.total,
        created_at: record.updated_at
      }
    };
  } else {
    return []; // Skip non-relevant updates
  }
}
// Supabase Database Webhook format (returns table INSERT)
else if (body.type === 'INSERT' && body.table === 'returns') {
  const record = body.record || {};
  payload = {
    alert_type: 'NEW_RETURN',
    data: {
      return_no: record.return_no,
      reason: record.reason,
      refund_method: record.refund_method,
      customer_id: record.customer_id,
      order_id: record.order_id,
      created_at: record.created_at
    }
  };
}
// Direct payload format (from custom triggers/functions)
// Expected: { alert_type: 'LOW_STOCK', data: { ... } }

return { json: payload };

// NEW ORDER alert for admin
const data = $input.first().json.data;
const adminPhone = $('Admin Config').first().json.ADMIN_PHONE;

const paymentLabel = {
  'UNPAID': '⏳ Unpaid',
  'SUBMITTED': '📸 Proof Submitted',
  'APPROVED': '✅ Paid',
  'ON_CREDIT': '🏷️ On Credit'
};

const message = `🔔 *NEW ORDER RECEIVED!*

📋 *${data.order_no}*
👤 ${data.customer_name}
📱 ${data.customer_phone}
💰 *RM ${parseFloat(data.total).toFixed(2)}*
💳 ${paymentLabel[data.payment_state] || data.payment_state}
📦 ${data.delivery_method === 'DELIVERY' ? 'Delivery' : 'Self Pickup'}
🕐 ${new Date(data.created_at).toLocaleString('en-MY', { timeZone: 'Asia/Kuala_Lumpur' })}

👉 Review: https://autolab.my/admin/orders`;

return {
  json: {
    phone: adminPhone,
    message: message
  }
};

// PAYMENT SUBMITTED alert for admin
const data = $input.first().json.data;
const adminPhone = $('Admin Config').first().json.ADMIN_PHONE;

const message = `💳 *PAYMENT PROOF SUBMITTED!*

📋 *${data.order_no}*
👤 ${data.customer_name}
💰 *RM ${parseFloat(data.total).toFixed(2)}*
🕐 ${new Date(data.created_at).toLocaleString('en-MY', { timeZone: 'Asia/Kuala_Lumpur' })}

⚡ *Action Required:* Verify payment
👉 https://autolab.my/admin/orders`;

return {
  json: {
    phone: adminPhone,
    message: message
  }
};

// LOW STOCK alert for admin
// Expected data: { products: [{ name, sku, current_stock, reorder_level }] }
const data = $input.first().json.data;
const adminPhone = $('Admin Config').first().json.ADMIN_PHONE;

const products = data.products || [];

if (products.length === 0) {
  return [];
}

let productList = products.slice(0, 10).map((p, i) => 
  `${i+1}. *${p.name}*\n   SKU: ${p.sku} | Stock: *${p.current_stock}* (Min: ${p.reorder_level})`
).join('\n\n');

const message = `⚠️ *LOW STOCK ALERT!*

${products.length} product(s) below reorder level:

${productList}${products.length > 10 ? `\n\n... and ${products.length - 10} more` : ''}

⚡ *Action Required:* Restock items
👉 https://autolab.my/admin/inventory`;

return {
  json: {
    phone: adminPhone,
    message: message
  }
};

// NEW RETURN REQUEST alert for admin
const data = $input.first().json.data;
const adminPhone = $('Admin Config').first().json.ADMIN_PHONE;

const reasonLabel = {
  'DEFECTIVE': '🔧 Defective/Damaged',
  'WRONG_ITEM': '❌ Wrong Item Received'
};

const methodLabel = {
  'ORIGINAL_PAYMENT': '💰 Refund',
  'EXCHANGE': '🔄 Exchange'
};

const message = `🔁 *NEW RETURN REQUEST!*

📋 *${data.return_no}*
📝 Reason: ${reasonLabel[data.reason] || data.reason}
🔁 Method: ${methodLabel[data.refund_method] || data.refund_method}
🕐 ${new Date(data.created_at).toLocaleString('en-MY', { timeZone: 'Asia/Kuala_Lumpur' })}

⚡ *Action Required:* Review return request
👉 https://autolab.my/admin/returns`;

return {
  json: {
    phone: adminPhone,
    message: message
  }
};
